// src/components/payment/PaymentModal.js
import { useState } from 'react';
import { enrollmentsService } from '../../services/enrollments';

// ─── Fake card formatter helpers ──────────────────────────────────────────────
const fmtCard   = (v) => v.replace(/\D/g,'').slice(0,16).replace(/(.{4})/g,'$1 ').trim();
const fmtExpiry = (v) => { const d = v.replace(/\D/g,'').slice(0,4); return d.length>2 ? d.slice(0,2)+'/'+d.slice(2) : d; };
const fmtCVV    = (v) => v.replace(/\D/g,'').slice(0,3);

const CARD_ICONS = { visa:'💳', mastercard:'💳', amex:'💳' };

const detectBrand = (num) => {
  const n = num.replace(/\s/g,'');
  if (n.startsWith('4'))   return 'visa';
  if (/^5[1-5]/.test(n))  return 'mastercard';
  if (/^3[47]/.test(n))   return 'amex';
  return null;
};

// ─── Component ────────────────────────────────────────────────────────────────
const PaymentModal = ({ course, onSuccess, onClose }) => {
  const [step, setStep]     = useState('form');   // 'form' | 'processing' | 'success' | 'error'
  const [errMsg, setErrMsg] = useState('');

  const [card, setCard] = useState({
    name:   '',
    number: '',
    expiry: '',
    cvv:    '',
  });

  const brand  = detectBrand(card.number);
  const price  = parseFloat(course.price).toFixed(2);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setCard((prev) => ({
      ...prev,
      name:   name === 'name'   ? value : prev.name,
      number: name === 'number' ? fmtCard(value)   : prev.number,
      expiry: name === 'expiry' ? fmtExpiry(value)  : prev.expiry,
      cvv:    name === 'cvv'    ? fmtCVV(value)     : prev.cvv,
    }));
  };

  const validate = () => {
    if (!card.name.trim())           return 'أدخل اسم حامل البطاقة';
    if (card.number.replace(/\s/g,'').length < 16) return 'رقم البطاقة غير مكتمل';
    if (card.expiry.length < 5)      return 'تاريخ الانتهاء غير مكتمل';
    if (card.cvv.length < 3)         return 'CVV غير مكتمل';
    return null;
  };

  const handlePay = async () => {
    const validationError = validate();
    if (validationError) { setErrMsg(validationError); return; }
    setErrMsg('');
    setStep('processing');

    // Simulate processing delay
    await new Promise((r) => setTimeout(r, 2000));

    try {
      // Enroll via backend (payment is fake but enrollment is real)
      await enrollmentsService.enroll(course.id);
      setStep('success');
    } catch (err) {
      const msg = err.response?.data?.non_field_errors?.[0] || 'فشلت عملية الدفع';
      setErrMsg(msg);
      setStep('error');
    }
  };

  // ── Processing screen ──
  if (step === 'processing') {
    return (
      <div style={s.overlay}>
        <div style={s.modal}>
          <div style={s.processingWrap}>
            <div style={s.spinner} />
            <h3 style={{ marginTop:20 }}>جاري معالجة الدفع...</h3>
            <p style={{ color:'#666' }}>لا تغلق هذه الصفحة</p>
          </div>
        </div>
      </div>
    );
  }

  // ── Success screen ──
  if (step === 'success') {
    return (
      <div style={s.overlay}>
        <div style={s.modal}>
          <div style={s.processingWrap}>
            <div style={s.successIcon}>✓</div>
            <h3 style={{ marginTop:16, color:'#155724' }}>تم الدفع بنجاح!</h3>
            <p style={{ color:'#666', marginBottom:24 }}>تم تسجيلك في الكورس</p>
            <button style={s.payBtn} onClick={onSuccess}>ابدأ التعلم الآن ▶</button>
          </div>
        </div>
      </div>
    );
  }

  // ── Error screen ──
  if (step === 'error') {
    return (
      <div style={s.overlay}>
        <div style={s.modal}>
          <div style={s.processingWrap}>
            <div style={s.errorIcon}>✕</div>
            <h3 style={{ marginTop:16, color:'#721c24' }}>فشلت العملية</h3>
            <p style={{ color:'#666', marginBottom:24 }}>{errMsg}</p>
            <button style={{ ...s.payBtn, background:'#6c757d' }} onClick={() => setStep('form')}>حاول مرة أخرى</button>
          </div>
        </div>
      </div>
    );
  }

  // ── Payment Form ──
  return (
    <div style={s.overlay} onClick={onClose}>
      <div style={s.modal} onClick={(e) => e.stopPropagation()}>

        {/* Header */}
        <div style={s.header}>
          <div>
            <h3 style={{ margin:0 }}>💳 إتمام الشراء</h3>
            <p style={{ margin:'4px 0 0', color:'#666', fontSize:14 }}>{course.title}</p>
          </div>
          <button style={s.closeBtn} onClick={onClose}>✕</button>
        </div>

        <div style={s.body}>
          {/* Order Summary */}
          <div style={s.summary}>
            <span>إجمالي الطلب</span>
            <span style={s.totalPrice}>{price} EGP</span>
          </div>

          {/* Fake Card UI */}
          <div style={s.cardPreview}>
            <div style={s.cardChip}>▪▪▪▪</div>
            <div style={s.cardNumber}>
              {card.number || '•••• •••• •••• ••••'}
            </div>
            <div style={s.cardBottom}>
              <div>
                <div style={s.cardLabel}>Card Holder</div>
                <div style={s.cardValue}>{card.name || 'YOUR NAME'}</div>
              </div>
              <div>
                <div style={s.cardLabel}>Expires</div>
                <div style={s.cardValue}>{card.expiry || 'MM/YY'}</div>
              </div>
              {brand && <div style={{ fontSize:28 }}>{CARD_ICONS[brand]}</div>}
            </div>
          </div>

          {/* Form */}
          <div style={s.field}>
            <label style={s.label}>اسم حامل البطاقة</label>
            <input style={s.input} name="name" placeholder="Ahmed Mohamed"
              value={card.name} onChange={handleChange} />
          </div>
          <div style={s.field}>
            <label style={s.label}>رقم البطاقة</label>
            <input style={s.input} name="number" placeholder="1234 5678 9012 3456"
              value={card.number} onChange={handleChange} inputMode="numeric" />
          </div>
          <div style={{ display:'flex', gap:12 }}>
            <div style={{ ...s.field, flex:1 }}>
              <label style={s.label}>تاريخ الانتهاء</label>
              <input style={s.input} name="expiry" placeholder="MM/YY"
                value={card.expiry} onChange={handleChange} inputMode="numeric" />
            </div>
            <div style={{ ...s.field, flex:1 }}>
              <label style={s.label}>CVV</label>
              <input style={s.input} name="cvv" placeholder="123" type="password"
                value={card.cvv} onChange={handleChange} inputMode="numeric" />
            </div>
          </div>

          {errMsg && <p style={s.errMsg}>⚠ {errMsg}</p>}

          <button style={s.payBtn} onClick={handlePay}>
            ادفع {price} EGP الآن 🔒
          </button>

          <p style={s.secureNote}>🔒 هذه بيئة تجريبية – لا يتم خصم أي مبالغ حقيقية</p>
        </div>
      </div>
    </div>
  );
};

// ─── Styles ───────────────────────────────────────────────────────────────────
const s = {
  overlay:  { position:'fixed', inset:0, background:'rgba(0,0,0,0.6)', display:'flex',
              alignItems:'center', justifyContent:'center', zIndex:2000 },
  modal:    { background:'#fff', borderRadius:16, width:'90%', maxWidth:440,
              overflow:'hidden', boxShadow:'0 25px 70px rgba(0,0,0,0.35)' },
  header:   { display:'flex', justifyContent:'space-between', alignItems:'flex-start',
              padding:'20px 24px', borderBottom:'1px solid #eee', background:'#f8f9fa' },
  closeBtn: { background:'none', border:'none', fontSize:20, cursor:'pointer', color:'#666', marginTop:2 },
  body:     { padding:24 },
  summary:  { display:'flex', justifyContent:'space-between', alignItems:'center',
              background:'#f0f4ff', borderRadius:8, padding:'12px 16px', marginBottom:20 },
  totalPrice:{ fontSize:22, fontWeight:700, color:'#007bff' },

  // Fake card
  cardPreview:{ background:'linear-gradient(135deg,#1a1a2e,#16213e)', borderRadius:16,
                padding:24, color:'#fff', marginBottom:20, minHeight:160, position:'relative' },
  cardChip:   { fontSize:18, letterSpacing:2, opacity:0.7, marginBottom:20 },
  cardNumber: { fontSize:18, letterSpacing:4, fontFamily:'monospace', marginBottom:20 },
  cardBottom: { display:'flex', justifyContent:'space-between', alignItems:'flex-end' },
  cardLabel:  { fontSize:10, opacity:0.6, textTransform:'uppercase', letterSpacing:1 },
  cardValue:  { fontSize:14, fontWeight:600, textTransform:'uppercase', letterSpacing:1 },

  field:    { marginBottom:14 },
  label:    { display:'block', fontSize:13, fontWeight:500, marginBottom:5, color:'#444' },
  input:    { width:'100%', padding:'10px 12px', borderRadius:8, border:'1px solid #ddd',
              fontSize:15, boxSizing:'border-box', outline:'none' },
  errMsg:   { color:'#dc3545', fontSize:13, margin:'0 0 12px' },
  payBtn:   { width:'100%', padding:'13px', background:'#007bff', color:'#fff', border:'none',
              borderRadius:10, fontSize:16, fontWeight:700, cursor:'pointer', marginTop:4 },
  secureNote:{ textAlign:'center', color:'#999', fontSize:12, marginTop:12 },

  // Processing / success / error
  processingWrap:{ padding:48, display:'flex', flexDirection:'column', alignItems:'center' },
  spinner: {
    width:52, height:52, borderRadius:'50%',
    border:'5px solid #e9ecef', borderTopColor:'#007bff',
    animation:'spin 0.9s linear infinite',
  },
  successIcon:{ width:60, height:60, borderRadius:'50%', background:'#d4edda',
                display:'flex', alignItems:'center', justifyContent:'center',
                fontSize:28, color:'#155724', fontWeight:700 },
  errorIcon:  { width:60, height:60, borderRadius:'50%', background:'#f8d7da',
                display:'flex', alignItems:'center', justifyContent:'center',
                fontSize:28, color:'#721c24', fontWeight:700 },
};

// Inject spinner keyframes once
if (typeof document !== 'undefined' && !document.getElementById('pm-spin')) {
  const style = document.createElement('style');
  style.id = 'pm-spin';
  style.innerHTML = '@keyframes spin { to { transform: rotate(360deg); } }';
  document.head.appendChild(style);
}

export default PaymentModal;
